#include<stdio.h>
#include<string.h>
#define INF (unsigned long long)1000000000000000001
int q, n, flen, slen, e;
unsigned long long k, f[100001];
char s1[200] = "What are you doing at the end of the world? Are you busy? Will you save us?";
char s2[200] = "What are you doing while sending xx? Are you busy? Will you send xx?";
char s3[200] = "What are you doing while sending x";
char s4[200] = "x? Are you busy? Will you send x";
char s5[200] = "x?";
void find(int d, long long jump){
	if (d == 0){
		printf("%c", s1[jump]);
		e = 1;
		return;
	}
	if (flen > jump){
		if (s3[jump] == 'x')printf("\"");
		else printf("%c", s3[jump]);
		e = 1;
	}
	else if (flen + f[d - 1] > jump){
		find(d - 1, jump - flen);

	}
	else if (flen + f[d - 1] + slen > jump){
		jump -= (flen + f[d - 1]);
		if (s4[jump] == 'x')printf("\"");
		else printf("%c", s4[jump]);
		e = 1;
	}
	else if (flen + f[d - 1] + slen + f[d - 1] > jump){
		find(d - 1, jump - flen - f[d - 1] - slen);
	}
	else{
		jump -= (flen + f[d - 1] + slen + f[d - 1]);
		if (s5[jump] == 'x')printf("\"");
		else printf("%c", s5[jump]);
		e = 1;
	}
	if (e)return;
}


int main()
{
	scanf("%d", &q);
	int len = strlen(s1);
	int len2 = strlen(s2);
	flen = strlen(s3);
	slen = strlen(s4);
	f[0] = len;
	for (int i = 1; i <= 100000; i++){
		if (f[i - 1] == INF)f[i] = INF;
		f[i] = f[i - 1] * 2 + len2;
		if (f[i] >= INF)f[i] = INF;
	}
	while (q--){
		scanf("%d%lld", &n, &k);
		k--;
		e = 0;
		if (f[n] <= k)printf(".");
		else find(n, k);
	}
	printf("\n");
}

