fn main() {
    let mut stdin = String::new();
    std::io::Read::read_to_string(&mut std::io::stdin(), &mut stdin).unwrap();
    let mut stdin = stdin.split_whitespace();
    let mut get = || stdin.next().unwrap();
    macro_rules! get { () => (get().parse().unwrap()) }


    let f0 = b"What are you doing at the end of the world? Are you busy? Will you save us?";
    let f1a = b"What are you doing while sending \"";
    let f1b = b"\"? Are you busy? Will you send \"";
    let f1c = b"\"?";

    let mut w = vec![0_u64; 100001];

    w[0] = f0.len() as u64;
    for i in 1..w.len() {
        w[i] = w[i-1] * 2 + (f1a.len() + f1b.len() + f1c.len()) as u64;
    }

    let q = get!();
    let mut v = vec![];
    for _ in 0..q {
        let mut n: usize = get!();
        let mut k: u64 = get!();
        k -= 1;
        loop {
            if k > w[n] {
                v.push(b'.');
                break;
            } else if n == 0 {
                v.push(f0[k as usize]);
                break;
            } else {
                n -= 1;
                if k < f1a.len() as u64 {
                    v.push(f1a[k as usize]);
                    break;
                }
                k -= f1a.len() as u64;
                if k < w[n] {
                    continue;
                }
                k -= w[n];
                if k < f1b.len() as u64 {
                    v.push(f1b[k as usize]);
                    break;
                }
                k -= f1b.len() as u64;
                if k < w[n] {
                    continue;
                }
                k -= w[n];
                if k < f1c.len() as u64 {
                    v.push(f1c[k as usize]);
                    break;
                }
                v.push(b'.');
                break;
            }
        }
    }
    println!("{}", String::from_utf8(v).unwrap());
}
